#include<bits/stdc++.h>
using namespace std;
char tr[30];
int n;
void dfs(int k)
{
    cout<<tr[k];
    if(2*k<=n) dfs(2*k);
    if(2*k+1<=n) dfs(2*k+1);
}
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        char x,y,z;
        cin>>x>>y>>z;
        tr[i]=x;
    }
    dfs(1);
    return 0;
}
